"""
API de Firma Digital de PDFs — Plan International v3.1
- Sello Plan International embebido (no se envía en cada request)
- Fuente LiberationSerif (Times New Roman)
- Todo en RAM — sin archivos temporales en disco
"""

from fastapi import FastAPI, HTTPException, Header
from pydantic import BaseModel
from typing import Optional
import base64, io, os, hashlib, datetime
import numpy as np

from pypdf import PdfReader, PdfWriter
from reportlab.pdfgen import canvas
from reportlab.lib.utils import ImageReader
from reportlab.pdfbase import pdfmetrics
from reportlab.pdfbase.ttfonts import TTFont
from PIL import Image

# ── Config ────────────────────────────────────────────────────────────
API_KEY         = os.getenv("API_KEY", "planint-firma-2026")
UMBRAL_PALABRAS = 15
UMBRAL_PIXELS   = 100_000

# Fuentes (LiberationSerif = Times New Roman, disponible en Render/Ubuntu)
try:
    pdfmetrics.registerFont(TTFont("LiberSerif",  "/usr/share/fonts/truetype/liberation/LiberationSerif-Regular.ttf"))
    pdfmetrics.registerFont(TTFont("LiberSerifB", "/usr/share/fonts/truetype/liberation/LiberationSerif-Bold.ttf"))
    USAR_SERIF = True
except:
    USAR_SERIF = False

# Coordenadas calibradas para Purchase Orders Plan International (A4)
SELLO_X=46; SELLO_Y=16; SELLO_W=44; SELLO_H=40
T1_X=95;  T2_X=258; T3_X=415
Y1=49; Y2=41; Y3=33; Y4=25; Y5=17
MARCA_Y=7

# ── Sello embebido (imagen fija Plan International) ───────────────────
SELLO_B64 = ""
SELLO_BYTES = base64.b64decode(SELLO_B64)

# ── App ───────────────────────────────────────────────────────────────
app = FastAPI(
    title="API Firma PDF — Plan International",
    description="""
Firma digitalmente PDFs de Purchase Orders.
- **Páginas con recuadro**: firma con sello, nombre, cargo, realizado por y fecha/hora
- **Páginas vacías**: marca diagonal \'Cara sin datos\' + ID único
- **Sello**: imagen Plan International embebida — no se envía en el request
- **Fecha y hora**: registradas automáticamente por el sistema
    """,
    version="3.1.0"
)

# ── Modelos ───────────────────────────────────────────────────────────
class FirmaRequest(BaseModel):
    pdf_base64: str               # PDF a firmar en Base64

    nombre_supervisor: str        # "Jhumers Mauricio"    ← User().FullName
    cargo_supervisor: str         # "Analista de TI"      ← User().JobTitle
    user_id: str                  # "abc123-..."           ← User().EntraObjectId

    realizado_por: str            # "Carlos Mendoza"
    cargo_realizado_por: str      # "Responsable de compras"

class FirmaResponse(BaseModel):
    success: bool
    pdf_firmado_base64: str       # PDF firmado listo para guardar en SharePoint
    firma_id: str                 # ID único de esta firma (ej: "A3F72603")
    paginas_firmadas: int
    paginas_marcadas: int
    mensaje: str

# ── Helpers ───────────────────────────────────────────────────────────
def f(bold=False):
    if USAR_SERIF: return "LiberSerifB" if bold else "LiberSerif"
    return "Helvetica-Bold" if bold else "Helvetica"

def generar_firma_id(nombre: str, fecha: str) -> str:
    return hashlib.sha256(f"{nombre}-{fecha}-{datetime.datetime.now().isoformat()}".encode()).hexdigest()[:8].upper()

def detectar_firmable(page) -> tuple[bool, str]:
    text      = page.extract_text() or ""
    words     = [w for w in text.split() if len(w) > 1]
    resources = page.get("/Resources", {})
    has_fonts = bool(resources.get("/Font", {}))
    xobjects  = resources.get("/XObject", {})
    total_px  = 0
    for _, obj in xobjects.items():
        try:
            xobj = obj.get_object()
            if xobj.get("/Subtype") == "/Image":
                total_px += int(xobj.get("/Width",0)) * int(xobj.get("/Height",0))
        except: pass
    if has_fonts:
        if len(words) >= UMBRAL_PALABRAS and "Signed on behalf" in text:
            return True, f"texto con recuadro ({len(words)} palabras)"
        return False, f"texto sin recuadro o vacío ({len(words)} palabras)"
    if total_px >= UMBRAL_PIXELS:
        return True, f"escaneado con contenido ({total_px:,} px)"
    return False, f"escaneado vacío ({total_px:,} px)"

def overlay_firma(pw, ph, nombre_sup, cargo_sup, realizado_por,
                  cargo_realizado, user_id, fecha_hora, firma_id) -> bytes:
    pkt = io.BytesIO()
    c   = canvas.Canvas(pkt, pagesize=(pw, ph))

    # Sello embebido
    try:
        img = Image.open(io.BytesIO(SELLO_BYTES)).convert("RGBA")
        buf = io.BytesIO(); img.save(buf, format="PNG"); buf.seek(0)
        c.drawImage(ImageReader(buf), SELLO_X, SELLO_Y,
                    width=SELLO_W, height=SELLO_H, mask="auto")
    except: pass

    # Bloque izquierdo — supervisor
    c.setFont(f(),    5.5); c.setFillColorRGB(.10,.10,.10); c.drawString(T1_X, Y1, "Firmado digitalmente por")
    c.setFont(f(True),6.5); c.setFillColorRGB(0,0,0);       c.drawString(T1_X, Y2, nombre_sup)
    c.setFont(f(),    6.0); c.setFillColorRGB(.15,.15,.15); c.drawString(T1_X, Y3, cargo_sup + ".")
    c.setFont(f(),    5.5); c.setFillColorRGB(.20,.20,.20)
    c.drawString(T1_X, Y4, "Motivo:Aprobación")
    c.drawString(T1_X, Y5, user_id)

    # Bloque centro — realizado por
    c.setFont(f(),    6.0); c.setFillColorRGB(.15,.15,.15); c.drawString(T2_X, Y2, "Realizado por")
    c.setFont(f(True),6.5); c.setFillColorRGB(0,0,0);       c.drawString(T2_X, Y3, realizado_por)
    c.setFont(f(),    6.0); c.setFillColorRGB(.20,.20,.20); c.drawString(T2_X, Y4, cargo_realizado)

    # Bloque derecho — fecha y hora en una línea
    c.setFont(f(True),6.5); c.setFillColorRGB(0,0,0); c.drawString(T3_X, Y2, fecha_hora)

    # Marca de autenticidad
    marca = f"ID:{firma_id}  ·  Firmado digitalmente  ·  Plan International  ·  {fecha_hora}"
    c.setFont(f(), 4.5); c.setFillColorRGB(.52,.52,.52)
    c.drawString(pw/2 - len(marca)*2.4/2, MARCA_Y, marca)

    c.save(); pkt.seek(0)
    return pkt.read()

def overlay_blanco(pw, ph, firma_id, fecha_hora) -> bytes:
    pkt = io.BytesIO()
    c   = canvas.Canvas(pkt, pagesize=(pw, ph))
    c.saveState()
    c.setFont(f(True), 52); c.setFillColorRGB(.72,.72,.72)
    c.translate(pw/2, ph/2); c.rotate(35)
    c.drawCentredString(0, 0, "Cara sin datos")
    c.restoreState()
    marca = f"ID:{firma_id}  ·  Sin contenido  ·  Plan International  ·  {fecha_hora}"
    c.setFont(f(), 4.5); c.setFillColorRGB(.52,.52,.52)
    c.drawString(pw/2 - len(marca)*2.4/2, 10, marca)
    c.save(); pkt.seek(0)
    return pkt.read()

# ── Endpoints ─────────────────────────────────────────────────────────
@app.get("/", tags=["Health"])
def root():
    return {"status": "ok", "version": "3.1.0", "serif": USAR_SERIF}

@app.get("/health", tags=["Health"])
def health():
    return {"status": "ok", "ts": datetime.datetime.now().isoformat(), "serif": USAR_SERIF}

@app.post("/firmar", response_model=FirmaResponse, tags=["Firma"])
def firmar_pdf(req: FirmaRequest, x_api_key: Optional[str] = Header(None)):
    """
    Firma todas las páginas válidas del PDF.
    Páginas vacías reciben marca \'Cara sin datos\'.
    Fecha y hora registradas automáticamente.
    Sello Plan International embebido — no se envía en el request.
    """
    if x_api_key != API_KEY:
        raise HTTPException(401, "API Key inválida. Header requerido: x-api-key")

    try:    pdf_bytes = base64.b64decode(req.pdf_base64)
    except: raise HTTPException(400, "pdf_base64 inválido")

    ahora      = datetime.datetime.now()
    fecha_hora = ahora.strftime("%d/%m/%Y %H:%M")
    firma_id   = generar_firma_id(req.nombre_supervisor, ahora.strftime("%d/%m/%Y"))

    try:    reader = PdfReader(io.BytesIO(pdf_bytes)); writer = PdfWriter()
    except Exception as e: raise HTTPException(400, f"Error leyendo PDF: {e}")

    firmadas = 0; marcadas = 0

    for i, page in enumerate(reader.pages):
        firmable, _ = detectar_firmable(page)
        pw = float(page.mediabox.width)
        ph = float(page.mediabox.height)

        if firmable:
            ovl = overlay_firma(pw, ph,
                req.nombre_supervisor, req.cargo_supervisor,
                req.realizado_por, req.cargo_realizado_por,
                req.user_id, fecha_hora, firma_id)
            firmadas += 1
        else:
            ovl = overlay_blanco(pw, ph, firma_id, fecha_hora)
            marcadas += 1

        page.merge_page(PdfReader(io.BytesIO(ovl)).pages[0])
        writer.add_page(page)

    out = io.BytesIO()
    writer.write(out); out.seek(0)

    return FirmaResponse(
        success            = True,
        pdf_firmado_base64 = base64.b64encode(out.read()).decode(),
        firma_id           = firma_id,
        paginas_firmadas   = firmadas,
        paginas_marcadas   = marcadas,
        mensaje            = f"OK. Firmadas:{firmadas} | Sin datos:{marcadas} | ID:{firma_id}"
    )
